var util = objParse(String(java.get("util")))

function objParse(obj) {
    return JSON.parse(obj, (n, v) => {
        if (typeof v == "string" && v.match("()")) {
            return eval(`(${v})`)
        }
        return v;
    })
}

function getContent(res) {
    let content = res.content
    if (util.SHOW_COMMENTS === true && res.desc !== "") {
        content = res.desc + "\n" + "â€”â€”â€”â€”â€”â€”â€”â€”â€”â€”\n".repeat(2) + content
    }

    // èژ·هڈ– [uploadedimage:] çڑ„ه›¾ç‰‡é“¾وژ¥
    // ه°†ه­کهœ¨çڑ„ pixiv ه›¾ç‰‡é“¾وژ¥و›؟وچ¢ن¸؛هڈ¯è®؟é—®çڑ„ç›´è؟‍
    if (res.images !== undefined && res.images !== null) {
        Object.keys(res.images).forEach((key) => {
            content = content.replace(`[uploadedimage:${key}]`, `<img src="${urlCoverUrl(res.images[key].origin)}">`)
        })
    }

    // èژ·هڈ– [pixivimage:] çڑ„ه›¾ç‰‡é“¾وژ¥ [pixivimage:1234] [pixivimage:1234-1]
    let matched = content.match(RegExp(/\[pixivimage:(\d+)-?(\d+)]/gm))
    if (matched) {
        for (let i in matched) {
            let illustId, order
            let matched2 = matched[i].match(RegExp("(\\d+)-?(\\d+)"))
            let temp = matched2[0].split("-")
            illustId = temp[0]
            if (temp.length >= 2) {
                order = temp[1]
            }
            content = content.replace(`${matched[i]}`, `<img src="${urlIllustOriginal(illustId, order)}">`)
        }
    }

    // و›؟وچ¢ Pixiv هˆ†é،µو ‡è®°ç¬¦هڈ· [newpage]
    matched = content.match(RegExp(/[ م€€]*\[newpage][ م€€]*/gm))
    if (matched) {
        for (let i in matched) {
            java.log(matched[i])
            content = content.replace(`${matched[i]}`, `${"<p>â€‹<p/>".repeat(3)}`)
        }
    }

    // و›؟وچ¢ Pixiv ç« èٹ‚و ‡è®°ç¬¦هڈ· [chapter:]
    matched = content.match(RegExp(/\[chapter:(.*?)]/gm))
    if (matched) {
        for (let i in matched) {
            let matched2 = matched[i].match(/\[chapter:(.*?)]/m)
            let chapter = matched2[1].trim()
            content = content.replace(`${matched[i]}`, `${chapter}<p>â€‹<p/>`)
        }
    }

    // و›؟وچ¢ Pixiv è·³è½¬é،µé‌¢و ‡è®°ç¬¦هڈ· [[jump:]]
    matched = content.match(RegExp(/\[jump:(\d+)]/gm))
    if (matched) {
        for (let i in matched) {
            let page = matched[i].match(/\d+/)
            content = content.replace(`${matched[i]}`, `\n\nè·³è½¬è‡³ç¬¬${page}èٹ‚`)
        }
    }

    // و›؟وچ¢ Pixiv é“¾وژ¥و ‡è®°ç¬¦هڈ· [[jumpuri: > ]]
    matched = content.match(RegExp(/\[\[jumpuri:(.*?)>(.*?)]]/gm))
    if (matched) {
        for (let i in matched) {
            let matched2 = matched[i].match(/\[\[jumpuri:(.*?)>(.*?)]]/m)
            let matchedText = matched2[0]
            let urlName = matched2[1].trim()
            let urlLink = matched2[2].trim()
            // éک…è¯»ن¸چو”¯وŒپè¶…é“¾وژ¥
            // content = content.replace(`${matchedText}`, `<a href=${urlLink}>${urlName}</a>`)
            if (urlLink === urlName) {
                content = content.replace(`${matchedText}`, `${urlName}`)
            } else {
                content = content.replace(`${matchedText}`, `${urlName}: ${urlLink}`)
            }
        }
    }

    // و›؟وچ¢ Pixiv و³¨éں³و ‡è®°ç¬¦هڈ· [[rb: > ]]
    matched = content.match(RegExp(/\[\[rb:(.*?)>(.*?)]]/gm))
    if (matched) {
        for (let i in matched) {
            let matched2 = matched[i].match(/\[\[rb:(.*?)>(.*?)]]/m)
            let matchedText = matched2[0]
            let kanji = matched2[1].trim()
            let kana = matched2[2].trim()

            if (!util.REPLACE_TITLE_MARKS) {
                // é»کè®¤و›؟وچ¢وˆگï¼ˆو‹¬هڈ·ï¼‰
                content = content.replace(`${matchedText}`, `${kanji}ï¼ˆ${kana}ï¼‰`)
            } else {
                let reg = RegExp("[\\u4E00-\\u9FFF]+", "g");
                if (reg.test(kana)) {
                    // kanaن¸؛ن¸­و–‡ï¼Œهˆ™و›؟وچ¢ه›‍م€ٹن¹¦هگچهڈ·م€‹
                    content = content.replace(`${matchedText}`, `${kanji}م€ٹ${kana}م€‹`)
                } else {
                    // éک…è¯»ن¸چو”¯وŒپ <ruby> <rt> و³¨éں³
                    // content = content.replace(`${matchedText}`, `<ruby>${kanji}<rt>${kana}</rt></ruby>`)
                    content = content.replace(`${matchedText}`, `${kanji}ï¼ˆ${kana}ï¼‰`)
                }
            }
        }
    }
    return content
}

(() => {
    return getContent(util.getNovelRes(result))
})()

